Checking only minimum length is dangerously insufficient and leaves your application vulnerable to credential attacks. The 2023 Norton LifeLock breach demonstrated how weak password policies can compromise hundreds of thousands of accounts.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const app = express();

app.use(express.json());

app.post('/api/register', async (req, res) => {
  const { username, password, email } = req.body;

  // VULNERABLE: Only checking minimum length
  if (password.length < 6) {
    return res.status(400).json({ error: 'Password must be at least 6 characters' });
  }

  // VULNERABLE: Accepting any password that meets length
  const hashedPassword = await bcrypt.hash(password, 10);

  // Save user to database (simplified)
  const user = { username, email, password: hashedPassword };
  // await db.users.insert(user);

  res.status(201).json({ message: 'User registered successfully' });
});

app.listen(3000);
```

**Attack Payloads that would succeed**:
```text
password: "123456"      (most common password)
password: "password"    (second most common)
password: "qwerty"      (keyboard pattern)
password: "abc123"      (simple alphanumeric)
password: "john2024"    (username + year)
```

**Why This Is Dangerous**:
- Allows the most common passwords (123456, password, qwerty) which appear in all breach databases
- No complexity requirements means passwords are easily guessed or cracked
- Attackers use automated tools with lists of millions of common passwords
- Credential stuffing attacks succeed when users reuse weak passwords across sites
- A 6-character lowercase password can be brute-forced in under 1 second

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const zxcvbn = require('zxcvbn'); // Dropbox's password strength estimator
const app = express();

app.use(express.json());

// Common password blocklist (use a comprehensive list in production)
const COMMON_PASSWORDS = new Set([
  '123456', 'password', '123456789', 'qwerty', 'abc123',
  'password1', '12345678', 'letmein', 'welcome', 'monkey'
]);

function validatePassword(password, username, email) {
  const errors = [];

  // Minimum length (NIST recommends 8+, consider 12+)
  if (password.length < 12) {
    errors.push('Password must be at least 12 characters long');
  }

  // Maximum length (prevent DoS via bcrypt)
  if (password.length > 128) {
    errors.push('Password must not exceed 128 characters');
  }

  // Check against common passwords
  if (COMMON_PASSWORDS.has(password.toLowerCase())) {
    errors.push('This password is too common. Please choose a stronger password');
  }

  // Check for user-specific data
  const lowerPassword = password.toLowerCase();
  if (username && lowerPassword.includes(username.toLowerCase())) {
    errors.push('Password cannot contain your username');
  }
  if (email) {
    const emailPrefix = email.split('@')[0].toLowerCase();
    if (lowerPassword.includes(emailPrefix)) {
      errors.push('Password cannot contain your email address');
    }
  }

  // Use zxcvbn for realistic strength estimation
  const strength = zxcvbn(password, [username, email].filter(Boolean));
  if (strength.score < 3) {
    errors.push(`Password is too weak: ${strength.feedback.warning || 'Please choose a stronger password'}`);
    if (strength.feedback.suggestions.length > 0) {
      errors.push(...strength.feedback.suggestions);
    }
  }

  return { isValid: errors.length === 0, errors, score: strength.score };
}

app.post('/api/register', async (req, res) => {
  const { username, password, email } = req.body;

  // Validate password strength
  const validation = validatePassword(password, username, email);
  if (!validation.isValid) {
    return res.status(400).json({ 
      error: 'Password does not meet security requirements',
      details: validation.errors
    });
  }

  // Hash with appropriate cost factor
  const hashedPassword = await bcrypt.hash(password, 12);

  const user = { username, email, password: hashedPassword };
  // await db.users.insert(user);

  res.status(201).json({ message: 'User registered successfully' });
});

app.listen(3000);
```

**Key Security Controls**:
- **zxcvbn strength estimation**: Uses realistic entropy calculation considering patterns, dictionary words, and keyboard sequences rather than arbitrary complexity rules
- **Common password blocklist**: Prevents the most frequently breached passwords regardless of length/complexity
- **Context-aware validation**: Rejects passwords containing username or email to prevent obvious guesses
- **Appropriate bcrypt cost**: Uses cost factor 12 (about 250ms) to slow brute-force attacks

Excellent question! Checking passwords against breach databases is critical because 65% of users reuse passwords. The Have I Been Pwned (HIBP) API uses k-Anonymity so you never send the full password hash—only the first 5 characters of the SHA-1 hash.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const zxcvbn = require('zxcvbn');
const axios = require('axios');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
app.use(express.json());

// Configure secure logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Rate limiting for registration endpoint
const registerLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 registration attempts per window
  message: { error: 'Too many registration attempts. Please try again later.' },
  standardHeaders: true,
  legacyHeaders: false
});

// k-Anonymity password breach check via HIBP API
async function checkPasswordBreached(password) {
  try {
    // Create SHA-1 hash of password
    const sha1Hash = crypto
      .createHash('sha1')
      .update(password)
      .digest('hex')
      .toUpperCase();

    // Split hash: first 5 chars (prefix) and rest (suffix)
    const prefix = sha1Hash.substring(0, 5);
    const suffix = sha1Hash.substring(5);

    // Query HIBP API with only the prefix (k-Anonymity)
    const response = await axios.get(
      `https://api.pwnedpasswords.com/range/${prefix}`,
      {
        headers: {
          'User-Agent': 'SecureApp-PasswordChecker/1.0',
          'Add-Padding': 'true' // Prevents response size analysis
        },
        timeout: 5000
      }
    );

    // Search for our suffix in the response
    const hashes = response.data.split('\r\n');
    for (const hash of hashes) {
      const [hashSuffix, count] = hash.split(':');
      if (hashSuffix === suffix) {
        return { breached: true, count: parseInt(count, 10) };
      }
    }

    return { breached: false, count: 0 };
  } catch (error) {
    // Log error but don't block registration if API is unavailable
    logger.warn('HIBP API check failed', { error: error.message });
    return { breached: false, count: 0, apiError: true };
  }
}

// Comprehensive password validation
async function validatePasswordComprehensive(password, username, email) {
  const result = {
    isValid: true,
    errors: [],
    warnings: [],
    score: 0,
    breachCount: 0
  };

  // Length requirements (NIST SP 800-63B compliant)
  if (password.length < 12) {
    result.errors.push('Password must be at least 12 characters');
    result.isValid = false;
  }
  if (password.length > 128) {
    result.errors.push('Password must not exceed 128 characters');
    result.isValid = false;
  }

  // Check for Unicode normalization issues
  const normalizedPassword = password.normalize('NFKC');
  if (normalizedPassword !== password) {
    result.warnings.push('Password contains characters that may be normalized');
  }

  // Context-aware checks
  const lowerPassword = password.toLowerCase();
  if (username && lowerPassword.includes(username.toLowerCase())) {
    result.errors.push('Password cannot contain your username');
    result.isValid = false;
  }

  // zxcvbn strength check
  const strength = zxcvbn(password, [username, email].filter(Boolean));
  result.score = strength.score;

  if (strength.score < 3) {
    result.errors.push(strength.feedback.warning || 'Password is too weak');
    result.errors.push(...strength.feedback.suggestions);
    result.isValid = false;
  }

  // HIBP breach database check
  const breachCheck = await checkPasswordBreached(password);
  if (breachCheck.breached) {
    result.breachCount = breachCheck.count;
    result.errors.push(
      `This password has been exposed in ${breachCheck.count.toLocaleString()} data breaches. Please choose a different password.`
    );
    result.isValid = false;
  }
  if (breachCheck.apiError) {
    result.warnings.push('Breach database check unavailable - proceeding with other validations');
  }

  return result;
}

// Registration endpoint with full security controls
app.post('/api/register', registerLimiter, async (req, res) => {
  const startTime = Date.now();
  const { username, password, email } = req.body;
  const clientIP = req.ip;

  // Input presence validation
  if (!username || !password || !email) {
    logger.info('Registration failed: missing fields', { clientIP });
    return res.status(400).json({ error: 'All fields are required' });
  }

  try {
    // Comprehensive password validation
    const validation = await validatePasswordComprehensive(password, username, email);

    if (!validation.isValid) {
      logger.info('Registration failed: weak password', { 
        clientIP,
        username,
        score: validation.score,
        breached: validation.breachCount > 0
      });

      return res.status(400).json({
        error: 'Password does not meet security requirements',
        details: validation.errors,
        warnings: validation.warnings,
        strengthScore: validation.score
      });
    }

    // Hash password with adaptive cost factor
    const BCRYPT_COST = process.env.NODE_ENV === 'production' ? 12 : 10;
    const hashedPassword = await bcrypt.hash(password, BCRYPT_COST);

    // Store user (implementation depends on your database)
    const user = {
      username,
      email: email.toLowerCase(),
      password: hashedPassword,
      createdAt: new Date(),
      passwordChangedAt: new Date(),
      failedLoginAttempts: 0
    };
    // await db.users.insert(user);

    // Security audit log (never log passwords)
    logger.info('User registered successfully', {
      clientIP,
      username,
      email: email.replace(/(.{2}).*(@.*)/, '$1***$2'), // Partially mask email
      passwordScore: validation.score,
      duration: Date.now() - startTime
    });

    res.status(201).json({ 
      message: 'Registration successful',
      passwordStrength: validation.score
    });

  } catch (error) {
    logger.error('Registration error', { 
      clientIP, 
      error: error.message,
      stack: error.stack 
    });
    res.status(500).json({ error: 'Registration failed. Please try again.' });
  }
});

// Password change endpoint with additional security
app.post('/api/change-password', async (req, res) => {
  const { currentPassword, newPassword } = req.body;
  const userId = req.user?.id; // From authentication middleware

  if (!userId) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  // Prevent password reuse
  // const passwordHistory = await db.passwordHistory.find({ userId });
  // Check newPassword against history...

  // Validate new password
  const validation = await validatePasswordComprehensive(newPassword, req.user.username, req.user.email);

  if (!validation.isValid) {
    return res.status(400).json({
      error: 'New password does not meet requirements',
      details: validation.errors
    });
  }

  // Additional check: new password shouldn't be too similar to old
  // Use string similarity algorithm if needed

  logger.info('Password changed', { userId, clientIP: req.ip });
  res.json({ message: 'Password changed successfully' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

**Defense in Depth Layers**:

1. **k-Anonymity Breach Check**:
```javascript
// Only send first 5 chars of hash - API returns all matches
const prefix = sha1Hash.substring(0, 5);
// Our full hash never leaves the server
// We compare locally against returned suffixes
```

2. **Rate Limiting**:
```javascript
const registerLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5, // Prevents automated account creation
  standardHeaders: true
});
```

3. **Security Audit Logging**:
```javascript
logger.info('Registration failed: weak password', { 
  clientIP,
  username,
  score: validation.score,
  breached: validation.breachCount > 0
  // NEVER log the actual password
});
```

**Additional Protections**:
- **Graceful degradation**: If HIBP API is unavailable, other validations still run
- **Unicode normalization**: Handles potential bypass via Unicode lookalike characters
- **Password history**: Prevents cycling back to previously compromised passwords
- **Timing-safe comparison**: bcrypt.compare is already timing-safe
- **Adaptive cost factor**: Higher bcrypt cost in production vs development
- **Masked PII in logs**: Email addresses partially redacted in audit logs

Your concern is valid. Without rate limiting, login endpoints are vulnerable to brute force and credential stuffing attacks. Attackers can attempt thousands of password combinations per second.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import java.sql.*;
import org.mindrot.jbcrypt.BCrypt;

public class LoginServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "dbpassword";

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                if (BCrypt.checkpw(password, storedHash)) {
                    HttpSession session = request.getSession(true);
                    session.setAttribute("user", username);
                    response.sendRedirect("/dashboard");
                    return;
                }
            }
            // No rate limiting - attackers can try unlimited passwords
            response.sendError(401, "Invalid credentials");
        } catch (SQLException e) {
            response.setStatus(500);
        }
    }
}
```

**Attack Payload**:
```bash
# Hydra brute force attack - 1000+ attempts per minute
hydra -l admin -P /usr/share/wordlists/rockyou.txt \
  -t 64 -f http-post-form \
  "example.com/login:username=^USER^&password=^PASS^:Invalid credentials"

# Credential stuffing with known breached credentials
for cred in $(cat breached_creds.txt); do
  curl -X POST https://target.com/login \
    -d "username=${cred%%:*}&password=${cred##*:}"
done
```

**Why This Is Dangerous**:
- Attackers can attempt unlimited login combinations without delay
- Credential stuffing attacks using breached password databases succeed frequently (0.1-2% hit rate)
- Automated tools like Hydra can test 1000+ credentials per second
- No visibility into brute force attempts until accounts are compromised
- BCrypt slows down individual checks but doesn't prevent volume attacks

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.sql.*;
import java.time.Instant;
import java.util.concurrent.ConcurrentHashMap;
import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureLoginServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureLoginServlet.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "dbpassword";

    // Rate limiting: max 5 attempts per 15 minutes per IP
    private static final int MAX_ATTEMPTS = 5;
    private static final long LOCKOUT_DURATION_MS = 15 * 60 * 1000;
    private static final ConcurrentHashMap<String, LoginAttemptTracker> attemptsByIP = new ConcurrentHashMap<>();
    private static final ConcurrentHashMap<String, LoginAttemptTracker> attemptsByUsername = new ConcurrentHashMap<>();

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String clientIP = getClientIP(request);
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        // Check IP-based rate limit
        if (isRateLimited(attemptsByIP, clientIP)) {
            logger.warn("Rate limited IP: {} for user: {}", clientIP, username);
            response.setHeader("Retry-After", "900");
            response.sendError(429, "Too many login attempts. Try again later.");
            return;
        }

        // Check username-based rate limit (prevents distributed attacks)
        if (isRateLimited(attemptsByUsername, username)) {
            logger.warn("Rate limited username: {} from IP: {}", username, clientIP);
            response.setHeader("Retry-After", "900");
            response.sendError(429, "Too many login attempts. Try again later.");
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT id, password_hash FROM users WHERE username = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                String storedHash = rs.getString("password_hash");
                if (BCrypt.checkpw(password, storedHash)) {
                    // Clear rate limit trackers on success
                    attemptsByIP.remove(clientIP);
                    attemptsByUsername.remove(username);

                    HttpSession session = request.getSession(true);
                    session.setAttribute("user", username);
                    session.setAttribute("userId", rs.getInt("id"));

                    logger.info("Successful login: user={} ip={}", username, clientIP);
                    response.sendRedirect("/dashboard");
                    return;
                }
            }

            // Record failed attempt
            recordFailedAttempt(attemptsByIP, clientIP);
            recordFailedAttempt(attemptsByUsername, username);

            logger.warn("Failed login attempt: user={} ip={}", username, clientIP);

            // Constant-time response to prevent username enumeration
            Thread.sleep(100 + (long)(Math.random() * 200));
            response.sendError(401, "Invalid credentials");

        } catch (SQLException | InterruptedException e) {
            logger.error("Login error for user: {}", username, e);
            response.setStatus(500);
        }
    }

    private boolean isRateLimited(ConcurrentHashMap<String, LoginAttemptTracker> tracker, String key) {
        LoginAttemptTracker attempts = tracker.get(key);
        if (attempts == null) return false;
        return attempts.isLocked();
    }

    private void recordFailedAttempt(ConcurrentHashMap<String, LoginAttemptTracker> tracker, String key) {
        tracker.compute(key, (k, v) -> {
            if (v == null) v = new LoginAttemptTracker();
            v.recordFailure();
            return v;
        });
    }

    private String getClientIP(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private static class LoginAttemptTracker {
        private int attempts = 0;
        private long lockoutUntil = 0;

        synchronized void recordFailure() {
            attempts++;
            if (attempts >= MAX_ATTEMPTS) {
                lockoutUntil = System.currentTimeMillis() + LOCKOUT_DURATION_MS;
            }
        }

        synchronized boolean isLocked() {
            if (System.currentTimeMillis() > lockoutUntil) {
                attempts = 0;
                lockoutUntil = 0;
                return false;
            }
            return attempts >= MAX_ATTEMPTS;
        }
    }
}
```

**Key Security Controls**:
- **IP-based rate limiting**: Maximum 5 attempts per IP address within 15 minutes prevents single-source brute force
- **Username-based rate limiting**: Prevents distributed attacks targeting single accounts from multiple IPs
- **Exponential backoff via lockout**: After limit exceeded, user must wait before retrying
- **Constant-time responses**: Random delay prevents timing attacks for username enumeration
- **Comprehensive logging**: All login attempts logged with IP and username for security monitoring

Excellent point. In-memory rate limiting fails in distributed environments since each server maintains its own counters. Production systems need centralized rate limiting with Redis, plus additional layers of defense.

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import javax.servlet.annotation.WebServlet;
import java.sql.*;
import java.time.Duration;
import java.time.Instant;
import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import redis.clients.jedis.Jedis;
import redis.clients.jedis.JedisPool;
import com.fasterxml.jackson.databind.ObjectMapper;

@WebServlet("/api/login")
public class ProductionLoginServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(ProductionLoginServlet.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");
    private static final ObjectMapper mapper = new ObjectMapper();

    // Configuration - load from environment
    private static final String REDIS_HOST = System.getenv().getOrDefault("REDIS_HOST", "localhost");
    private static final JedisPool jedisPool = new JedisPool(REDIS_HOST, 6379);

    // Rate limit tiers
    private static final int IP_LIMIT_PER_MINUTE = 10;
    private static final int IP_LIMIT_PER_HOUR = 100;
    private static final int USERNAME_LIMIT_PER_HOUR = 5;
    private static final int GLOBAL_LIMIT_PER_MINUTE = 1000;

    // Account lockout settings
    private static final int LOCKOUT_THRESHOLD = 5;
    private static final Duration LOCKOUT_DURATION = Duration.ofMinutes(30);
    private static final Duration PROGRESSIVE_DELAY_BASE = Duration.ofSeconds(2);

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        Instant requestTime = Instant.now();
        String requestId = java.util.UUID.randomUUID().toString();
        String clientIP = extractClientIP(request);
        String userAgent = request.getHeader("User-Agent");
        String username = sanitizeInput(request.getParameter("username"));
        String password = request.getParameter("password");

        // Set security headers
        setSecurityHeaders(response);

        try (Jedis jedis = jedisPool.getResource()) {
            // Layer 1: Global rate limit (DDoS protection)
            if (!checkGlobalRateLimit(jedis)) {
                auditLogger.warn("action=login_blocked reason=global_rate_limit ip={} requestId={}", 
                    clientIP, requestId);
                sendRateLimitResponse(response, 60);
                return;
            }

            // Layer 2: IP-based rate limiting (per-minute and per-hour)
            RateLimitResult ipLimit = checkIPRateLimit(jedis, clientIP);
            if (!ipLimit.allowed) {
                auditLogger.warn("action=login_blocked reason=ip_rate_limit ip={} attempts={} requestId={}", 
                    clientIP, ipLimit.currentCount, requestId);
                sendRateLimitResponse(response, ipLimit.retryAfterSeconds);
                return;
            }

            // Layer 3: Username-based rate limiting
            if (username != null && !username.isEmpty()) {
                RateLimitResult usernameLimit = checkUsernameRateLimit(jedis, username);
                if (!usernameLimit.allowed) {
                    auditLogger.warn("action=login_blocked reason=username_rate_limit username={} ip={} requestId={}", 
                        username, clientIP, requestId);
                    // Don't reveal username exists - use same response
                    sendRateLimitResponse(response, usernameLimit.retryAfterSeconds);
                    return;
                }
            }

            // Layer 4: Account lockout check
            if (isAccountLocked(jedis, username)) {
                auditLogger.warn("action=login_blocked reason=account_locked username={} ip={} requestId={}", 
                    username, clientIP, requestId);
                // Constant response to prevent enumeration
                applyProgressiveDelay(jedis, clientIP);
                sendAuthFailure(response, "Invalid credentials");
                return;
            }

            // Layer 5: Bot/automation detection
            if (detectAutomation(request, jedis, clientIP)) {
                auditLogger.warn("action=login_blocked reason=automation_detected ip={} ua={} requestId={}", 
                    clientIP, userAgent, requestId);
                response.sendError(403, "Request blocked");
                return;
            }

            // Perform authentication
            AuthResult authResult = authenticate(username, password);

            if (authResult.success) {
                // Clear failure counters on success
                clearFailureCounters(jedis, clientIP, username);

                // Create secure session
                HttpSession session = request.getSession(true);
                session.setAttribute("userId", authResult.userId);
                session.setAttribute("username", username);
                session.setAttribute("loginTime", requestTime.toString());
                session.setAttribute("loginIP", clientIP);
                session.setMaxInactiveInterval(1800); // 30 minutes

                // Audit successful login
                auditLogger.info("action=login_success username={} ip={} ua={} requestId={}", 
                    username, clientIP, userAgent, requestId);

                // Publish login event for monitoring
                publishLoginEvent(jedis, username, clientIP, true);

                response.setStatus(200);
                response.setContentType("application/json");
                response.getWriter().write("{\"status\":\"success\",\"redirect\":\"/dashboard\"}");
            } else {
                // Record failure
                int failureCount = recordLoginFailure(jedis, clientIP, username);

                // Check if account should be locked
                if (failureCount >= LOCKOUT_THRESHOLD) {
                    lockAccount(jedis, username);
                    auditLogger.warn("action=account_locked username={} ip={} failures={} requestId={}", 
                        username, clientIP, failureCount, requestId);

                    // Send alert for potential attack
                    sendSecurityAlert("Account locked", username, clientIP, failureCount);
                }

                // Progressive delay based on failure count
                applyProgressiveDelay(jedis, clientIP);

                auditLogger.warn("action=login_failure username={} ip={} failures={} requestId={}", 
                    username, clientIP, failureCount, requestId);

                // Publish failure event for monitoring
                publishLoginEvent(jedis, username, clientIP, false);

                sendAuthFailure(response, "Invalid credentials");
            }

        } catch (Exception e) {
            logger.error("Login error requestId={}", requestId, e);
            response.sendError(500, "Internal server error");
        }
    }

    private boolean checkGlobalRateLimit(Jedis jedis) {
        String key = "ratelimit:global:" + Instant.now().getEpochSecond() / 60;
        long count = jedis.incr(key);
        if (count == 1) jedis.expire(key, 120);
        return count <= GLOBAL_LIMIT_PER_MINUTE;
    }

    private RateLimitResult checkIPRateLimit(Jedis jedis, String ip) {
        long currentMinute = Instant.now().getEpochSecond() / 60;
        long currentHour = Instant.now().getEpochSecond() / 3600;

        String minuteKey = "ratelimit:ip:minute:" + ip + ":" + currentMinute;
        String hourKey = "ratelimit:ip:hour:" + ip + ":" + currentHour;

        long minuteCount = jedis.incr(minuteKey);
        if (minuteCount == 1) jedis.expire(minuteKey, 120);

        long hourCount = jedis.incr(hourKey);
        if (hourCount == 1) jedis.expire(hourKey, 7200);

        if (minuteCount > IP_LIMIT_PER_MINUTE) {
            return new RateLimitResult(false, minuteCount, 60);
        }
        if (hourCount > IP_LIMIT_PER_HOUR) {
            return new RateLimitResult(false, hourCount, 3600);
        }
        return new RateLimitResult(true, minuteCount, 0);
    }

    private RateLimitResult checkUsernameRateLimit(Jedis jedis, String username) {
        long currentHour = Instant.now().getEpochSecond() / 3600;
        String key = "ratelimit:user:" + username.toLowerCase() + ":" + currentHour;

        long count = jedis.incr(key);
        if (count == 1) jedis.expire(key, 7200);

        if (count > USERNAME_LIMIT_PER_HOUR) {
            return new RateLimitResult(false, count, 3600);
        }
        return new RateLimitResult(true, count, 0);
    }

    private boolean isAccountLocked(Jedis jedis, String username) {
        return jedis.exists("locked:account:" + username.toLowerCase());
    }

    private void lockAccount(Jedis jedis, String username) {
        String key = "locked:account:" + username.toLowerCase();
        jedis.setex(key, (int) LOCKOUT_DURATION.getSeconds(), Instant.now().toString());
    }

    private int recordLoginFailure(Jedis jedis, String ip, String username) {
        String key = "failures:" + username.toLowerCase();
        long count = jedis.incr(key);
        if (count == 1) jedis.expire(key, (int) LOCKOUT_DURATION.getSeconds());
        return (int) count;
    }

    private void clearFailureCounters(Jedis jedis, String ip, String username) {
        jedis.del("failures:" + username.toLowerCase());
    }

    private void applyProgressiveDelay(Jedis jedis, String ip) throws InterruptedException {
        String key = "delay:" + ip;
        long failures = jedis.incr(key);
        if (failures == 1) jedis.expire(key, 3600);

        // Exponential backoff: 2^failures seconds, max 30 seconds
        long delayMs = Math.min(30000, (long) Math.pow(2, Math.min(failures, 5)) * 1000);
        Thread.sleep(delayMs + (long)(Math.random() * 500));
    }

    private boolean detectAutomation(HttpServletRequest request, Jedis jedis, String ip) {
