        }

        // Check request velocity (requests within 100ms window)
        String velocityKey = "velocity:" + ip;
        long timestamp = System.currentTimeMillis();
        jedis.zadd(velocityKey, timestamp, String.valueOf(timestamp));
        jedis.zremrangeByScore(velocityKey, 0, timestamp - 1000);
        jedis.expire(velocityKey, 60);

        long requestsInWindow = jedis.zcard(velocityKey);
        return requestsInWindow > 5; // More than 5 requests per second
    }

    private void publishLoginEvent(Jedis jedis, String username, String ip, boolean success) {
        String channel = "security:login_events";
        String event = String.format("{\"username\":\"%s\",\"ip\":\"%s\",\"success\":%b,\"timestamp\":\"%s\"}",
