Checking only minimum password length is dangerously insufficient. This was a contributing factor in the 2022 Dropbox breach where weak passwords enabled credential stuffing attacks. Let me show you the problem and the proper solution.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"net/http"
	"golang.org/x/crypto/bcrypt"
)

type User struct {
	Username string `json:"username"`
	Password string `json:"password"`
}

// VULNERABLE: Only checks minimum length
func validatePassword(password string) bool {
	return len(password) >= 6
}

func registerHandler(w http.ResponseWriter, r *http.Request) {
	var user User
	json.NewDecoder(r.Body).Decode(&user)

	// Weak validation - easily bypassed
	if !validatePassword(user.Password) {
		http.Error(w, "Password must be at least 6 characters", http.StatusBadRequest)
		return
	}

	// Password like "123456" or "password" would pass!
	hashedPassword, _ := bcrypt.GenerateFromPassword([]byte(user.Password), bcrypt.DefaultCost)

	// Store user with weak password...
	_ = hashedPassword
	w.WriteHeader(http.StatusCreated)
}
```

**Attack Payload**:
```text
Passwords that pass this weak validation:
- "123456" (most common password)
- "password"
- "qwerty"
- "aaaaaa"
- "111111"

These are in the top 100 of every password breach list and
will be cracked within seconds via dictionary attacks or
matched instantly via credential stuffing.
```

**Why This Is Dangerous**:
- Allows passwords from common breach lists (RockYou, LinkedIn, etc.)
- No complexity requirements means "123456" is valid
- No check against known compromised passwords
- Credential stuffing attacks succeed because users reuse weak passwords
- Dictionary attacks crack simple passwords in seconds even when hashed

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"errors"
	"net/http"
	"regexp"
	"strings"
	"unicode"

	"golang.org/x/crypto/bcrypt"
)

type User struct {
	Username string `json:"username"`
	Password string `json:"password"`
}

type PasswordPolicy struct {
	MinLength       int
	MaxLength       int
	RequireUpper    bool
	RequireLower    bool
	RequireDigit    bool
	RequireSpecial  bool
	DisallowCommon  bool
}

var DefaultPolicy = PasswordPolicy{
	MinLength:       12,
	MaxLength:       128,
	RequireUpper:    true,
	RequireLower:    true,
	RequireDigit:    true,
	RequireSpecial:  true,
	DisallowCommon:  true,
}

// Common passwords to block (in production, use a larger list or API)
var commonPasswords = map[string]bool{
	"password123": true, "123456789012": true, "qwerty123456": true,
	"letmein12345": true, "welcome12345": true, "admin1234567": true,
}

func validatePassword(password string, policy PasswordPolicy) error {
	if len(password) < policy.MinLength {
		return errors.New("password must be at least 12 characters")
	}
	if len(password) > policy.MaxLength {
		return errors.New("password exceeds maximum length")
	}

	var hasUpper, hasLower, hasDigit, hasSpecial bool
	for _, char := range password {
		switch {
		case unicode.IsUpper(char):
			hasUpper = true
		case unicode.IsLower(char):
			hasLower = true
		case unicode.IsDigit(char):
			hasDigit = true
		case unicode.IsPunct(char) || unicode.IsSymbol(char):
			hasSpecial = true
		}
	}

	if policy.RequireUpper && !hasUpper {
		return errors.New("password must contain uppercase letter")
	}
	if policy.RequireLower && !hasLower {
		return errors.New("password must contain lowercase letter")
	}
	if policy.RequireDigit && !hasDigit {
		return errors.New("password must contain a digit")
	}
	if policy.RequireSpecial && !hasSpecial {
		return errors.New("password must contain a special character")
	}

	// Check against common passwords
	if policy.DisallowCommon && commonPasswords[strings.ToLower(password)] {
		return errors.New("password is too common")
	}

	return nil
}

func registerHandler(w http.ResponseWriter, r *http.Request) {
	var user User
	if err := json.NewDecoder(r.Body).Decode(&user); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	if err := validatePassword(user.Password, DefaultPolicy); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// Use high bcrypt cost for password hashing
	hashedPassword, err := bcrypt.GenerateFromPassword([]byte(user.Password), 12)
	if err != nil {
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	_ = hashedPassword // Store securely
	w.WriteHeader(http.StatusCreated)
}
```

**Key Security Controls**:
- **Minimum 12 characters**: NIST SP 800-63B recommends minimum 8, but 12+ provides better protection against offline attacks
- **Complexity requirements**: Upper, lower, digit, and special characters increase entropy
- **Common password blocklist**: Prevents passwords that appear in breach databases
- **Maximum length limit**: Prevents DoS via extremely long passwords that slow bcrypt
- **Higher bcrypt cost (12)**: Increases computation time for attackers

Excellent questions. Checking against breach databases is now a NIST recommendation. Let me show you a production-ready implementation that includes HIBP integration, secure password changes, and proper account recovery.

**PRODUCTION PATTERN**:

```go
package auth

import (
	"context"
	"crypto/rand"
	"crypto/sha1"
	"crypto/subtle"
	"encoding/hex"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"net/http"
	"strings"
	"time"
	"unicode"

	"golang.org/x/crypto/bcrypt"
	"golang.org/x/time/rate"
)

var (
	ErrPasswordTooShort     = errors.New("password must be at least 12 characters")
	ErrPasswordTooLong      = errors.New("password exceeds 128 characters")
	ErrPasswordNoUpper      = errors.New("password must contain uppercase letter")
	ErrPasswordNoLower      = errors.New("password must contain lowercase letter")
	ErrPasswordNoDigit      = errors.New("password must contain a digit")
	ErrPasswordNoSpecial    = errors.New("password must contain special character")
	ErrPasswordCompromised  = errors.New("password found in data breach")
	ErrPasswordMatchesOld   = errors.New("new password cannot match previous passwords")
	ErrResetTokenInvalid    = errors.New("reset token is invalid or expired")
	ErrRateLimitExceeded    = errors.New("too many attempts, please try again later")
)

type PasswordService struct {
	httpClient    *http.Client
	logger        *slog.Logger
	rateLimiter   *rate.Limiter
	bcryptCost    int
	hibpEnabled   bool
	resetTokenTTL time.Duration
}

type PasswordPolicy struct {
	MinLength            int
	MaxLength            int
	RequireUppercase     bool
	RequireLowercase     bool
	RequireDigit         bool
	RequireSpecial       bool
	CheckBreachDatabase  bool
	PasswordHistoryCount int
}

type PasswordResetToken struct {
	Token     string
	UserID    string
	ExpiresAt time.Time
	Used      bool
}

func NewPasswordService(logger *slog.Logger) *PasswordService {
	return &PasswordService{
		httpClient: &http.Client{
			Timeout: 5 * time.Second,
		},
		logger:        logger,
		rateLimiter:   rate.NewLimiter(rate.Every(time.Second), 10),
		bcryptCost:    12,
		hibpEnabled:   true,
		resetTokenTTL: 1 * time.Hour,
	}
}

func DefaultPasswordPolicy() PasswordPolicy {
	return PasswordPolicy{
		MinLength:            12,
		MaxLength:            128,
		RequireUppercase:     true,
		RequireLowercase:     true,
		RequireDigit:         true,
		RequireSpecial:       true,
		CheckBreachDatabase:  true,
		PasswordHistoryCount: 5,
	}
}

// ValidatePassword performs comprehensive password validation
func (ps *PasswordService) ValidatePassword(ctx context.Context, password string, policy PasswordPolicy) error {
	// Length validation
	if len(password) < policy.MinLength {
		return ErrPasswordTooShort
	}
	if len(password) > policy.MaxLength {
		return ErrPasswordTooLong
	}

	// Complexity validation
	var hasUpper, hasLower, hasDigit, hasSpecial bool
	for _, r := range password {
		switch {
		case unicode.IsUpper(r):
			hasUpper = true
		case unicode.IsLower(r):
			hasLower = true
		case unicode.IsDigit(r):
			hasDigit = true
		case unicode.IsPunct(r) || unicode.IsSymbol(r):
			hasSpecial = true
		}
	}

	if policy.RequireUppercase && !hasUpper {
		return ErrPasswordNoUpper
	}
	if policy.RequireLowercase && !hasLower {
		return ErrPasswordNoLower
	}
	if policy.RequireDigit && !hasDigit {
		return ErrPasswordNoDigit
	}
	if policy.RequireSpecial && !hasSpecial {
		return ErrPasswordNoSpecial
	}

	// Check Have I Been Pwned database
	if policy.CheckBreachDatabase && ps.hibpEnabled {
		compromised, err := ps.checkHIBP(ctx, password)
		if err != nil {
			// Log but don't block registration if HIBP is unavailable
			ps.logger.Warn("HIBP check failed", "error", err)
		} else if compromised {
			return ErrPasswordCompromised
		}
	}

	return nil
}

// checkHIBP uses k-Anonymity model - only sends first 5 chars of SHA1 hash
func (ps *PasswordService) checkHIBP(ctx context.Context, password string) (bool, error) {
	// Rate limit HIBP requests
	if !ps.rateLimiter.Allow() {
		return false, ErrRateLimitExceeded
	}

	// SHA1 hash of password (HIBP requirement)
	hash := sha1.Sum([]byte(password))
	hashHex := strings.ToUpper(hex.EncodeToString(hash[:]))

	// K-Anonymity: only send first 5 characters
	prefix := hashHex[:5]
	suffix := hashHex[5:]

	req, err := http.NewRequestWithContext(ctx, "GET",
		fmt.Sprintf("https://api.pwnedpasswords.com/range/%s", prefix), nil)
	if err != nil {
		return false, fmt.Errorf("creating HIBP request: %w", err)
	}

	req.Header.Set("User-Agent", "SecureApp-PasswordChecker/1.0")
	req.Header.Set("Add-Padding", "true") // Prevent timing attacks

	resp, err := ps.httpClient.Do(req)
	if err != nil {
		return false, fmt.Errorf("HIBP request failed: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return false, fmt.Errorf("HIBP returned status: %d", resp.StatusCode)
	}

	body, err := io.ReadAll(io.LimitReader(resp.Body, 1024*1024)) // 1MB limit
	if err != nil {
		return false, fmt.Errorf("reading HIBP response: %w", err)
	}

	// Check if our suffix appears in the response
	lines := strings.Split(string(body), "\r\n")
	for _, line := range lines {
		parts := strings.Split(line, ":")
		if len(parts) >= 1 && subtle.ConstantTimeCompare([]byte(parts[0]), []byte(suffix)) == 1 {
			return true, nil // Password found in breach database
		}
	}

	return false, nil
}

// HashPassword creates a bcrypt hash with appropriate cost
func (ps *PasswordService) HashPassword(password string) (string, error) {
	hash, err := bcrypt.GenerateFromPassword([]byte(password), ps.bcryptCost)
	if err != nil {
		return "", fmt.Errorf("hashing password: %w", err)
	}
	return string(hash), nil
}

// VerifyPassword checks password against stored hash
func (ps *PasswordService) VerifyPassword(password, hash string) bool {
	err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password))
	return err == nil
}

// ChangePassword handles secure password change with history check
func (ps *PasswordService) ChangePassword(
	ctx context.Context,
	userID string,
	currentPassword string,
	newPassword string,
	currentHash string,
	previousHashes []string,
) (string, error) {
	// Verify current password first
	if !ps.VerifyPassword(currentPassword, currentHash) {
		ps.logger.Warn("password change failed: invalid current password",
			"user_id", userID)
		return "", errors.New("current password is incorrect")
	}

	// Validate new password against policy
	policy := DefaultPasswordPolicy()
	if err := ps.ValidatePassword(ctx, newPassword, policy); err != nil {
		return "", err
	}

	// Check against password history
	for _, oldHash := range previousHashes {
		if ps.VerifyPassword(newPassword, oldHash) {
			ps.logger.Warn("password change failed: matches previous password",
				"user_id", userID)
			return "", ErrPasswordMatchesOld
		}
	}

	// Hash and return new password
	newHash, err := ps.HashPassword(newPassword)
	if err != nil {
		return "", err
	}

	ps.logger.Info("password changed successfully", "user_id", userID)
	return newHash, nil
}

// GenerateResetToken creates a secure password reset token
func (ps *PasswordService) GenerateResetToken(userID string) (*PasswordResetToken, error) {
	// Generate 32 bytes of cryptographic randomness
	tokenBytes := make([]byte, 32)
	if _, err := rand.Read(tokenBytes); err != nil {
		return nil, fmt.Errorf("generating reset token: %w", err)
	}

	token := &PasswordResetToken{
		Token:     hex.EncodeToString(tokenBytes),
		UserID:    userID,
		ExpiresAt: time.Now().Add(ps.resetTokenTTL),
		Used:      false,
	}

	ps.logger.Info("password reset token generated",
		"user_id", userID,
		"expires_at", token.ExpiresAt)

	return token, nil
}

// ValidateResetToken verifies token and marks it as used
func (ps *PasswordService) ValidateResetToken(
	token *PasswordResetToken,
	providedToken string,
) error {
	if token == nil {
		return ErrResetTokenInvalid
	}

	// Constant-time comparison to prevent timing attacks
	if subtle.ConstantTimeCompare([]byte(token.Token), []byte(providedToken)) != 1 {
		return ErrResetTokenInvalid
	}

	if token.Used {
		ps.logger.Warn("attempted reuse of reset token", "user_id", token.UserID)
		return ErrResetTokenInvalid
	}

	if time.Now().After(token.ExpiresAt) {
		ps.logger.Warn("expired reset token used", "user_id", token.UserID)
		return ErrResetTokenInvalid
	}

	return nil
}

// ResetPassword performs password reset with token validation
func (ps *PasswordService) ResetPassword(
	ctx context.Context,
	token *PasswordResetToken,
	providedToken string,
	newPassword string,
) (string, error) {
	// Validate the reset token
	if err := ps.ValidateResetToken(token, providedToken); err != nil {
		return "", err
	}

	// Validate new password
	policy := DefaultPasswordPolicy()
	if err := ps.ValidatePassword(ctx, newPassword, policy); err != nil {
		return "", err
	}

	// Hash the new password
	newHash, err := ps.HashPassword(newPassword)
	if err != nil {
		return "", err
	}

	// Mark token as used (caller should persist this)
	token.Used = true

	ps.logger.Info("password reset completed", "user_id", token.UserID)
	return newHash, nil
}
