**Why This Is Dangerous**:
- Attackers can test millions of password combinations per hour
- Credential stuffing attacks use leaked password databases (billions of credentials available)
- No mechanism to detect or stop automated attacks
- Account lockout doesn't exist, so even strong passwords eventually fall

**SECURE VERSION**:

```php
<?php
require_once 'config.php';

class RateLimitedLoginController {
    private $pdo;
    private const MAX_ATTEMPTS = 5;
    private const LOCKOUT_DURATION = 900; // 15 minutes in seconds
    private const ATTEMPT_WINDOW = 300;   // 5 minutes in seconds

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function authenticate($username, $password, $clientIp) {
        // Check rate limit before any authentication
        if ($this->isRateLimited($username, $clientIp)) {
            $this->logSecurityEvent($username, $clientIp, 'rate_limited');
            return [
                'success' => false,
                'message' => 'Too many login attempts. Please try again later.',
                'retry_after' => self::LOCKOUT_DURATION
            ];
        }

        $stmt = $this->pdo->prepare(
            "SELECT id, username, password_hash FROM users WHERE username = ?"
        );
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($user && password_verify($password, $user['password_hash'])) {
            // Clear failed attempts on successful login
            $this->clearFailedAttempts($username, $clientIp);
            $this->logSecurityEvent($username, $clientIp, 'login_success');

            session_regenerate_id(true);
            $_SESSION['user_id'] = $user['id'];
            $_SESSION['username'] = $user['username'];
            return ['success' => true, 'message' => 'Login successful'];
        }

        // Record failed attempt
        $this->recordFailedAttempt($username, $clientIp);
        $this->logSecurityEvent($username, $clientIp, 'login_failed');

        return ['success' => false, 'message' => 'Invalid credentials'];
    }

    private function isRateLimited($username, $clientIp) {
        $stmt = $this->pdo->prepare("
            SELECT COUNT(*) as attempts FROM login_attempts 
            WHERE (username = ? OR ip_address = ?)
            AND attempt_time > DATE_SUB(NOW(), INTERVAL ? SECOND)
        ");
        $stmt->execute([$username, $clientIp, self::ATTEMPT_WINDOW]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);

        return $result['attempts'] >= self::MAX_ATTEMPTS;
    }

    private function recordFailedAttempt($username, $clientIp) {
        $stmt = $this->pdo->prepare("
            INSERT INTO login_attempts (username, ip_address, attempt_time)
            VALUES (?, ?, NOW())
        ");
        $stmt->execute([$username, $clientIp]);
    }

    private function clearFailedAttempts($username, $clientIp) {
        $stmt = $this->pdo->prepare("
            DELETE FROM login_attempts 
            WHERE username = ? OR ip_address = ?
        ");
        $stmt->execute([$username, $clientIp]);
    }

    private function logSecurityEvent($username, $clientIp, $event) {
        error_log(sprintf(
            "[SECURITY] %s: user=%s ip=%s time=%s",
            $event, $username, $clientIp, date('Y-m-d H:i:s')
        ));
    }
}
```

**Key Security Controls**:
- **Rate limiting by username AND IP**: Prevents both targeted and distributed attacks
- **Configurable thresholds**: 5 attempts per 5-minute window with 15-minute lockout
- **Security logging**: All authentication events are logged for monitoring and forensics
- **Graceful handling**: Returns appropriate error without revealing user existence

Excellent concerns! Distributed attacks bypass per-IP limits, and database queries add latency. Production systems need multiple defense layers including in-memory rate limiting, device fingerprinting, and behavioral analysis.

**PRODUCTION PATTERN**:

```php
<?php
require_once 'vendor/autoload.php';

use Predis\Client as RedisClient;

class ProductionLoginController {
    private PDO $pdo;
    private RedisClient $redis;
    private const IP_LIMIT = 10;           // Per IP
    private const USER_LIMIT = 5;          // Per username
    private const GLOBAL_LIMIT = 1000;     // Site-wide per minute
    private const WINDOW_SECONDS = 60;
    private const LOCKOUT_SECONDS = 900;

    public function __construct(PDO $pdo, RedisClient $redis) {
        $this->pdo = $pdo;
        $this->redis = $redis;
    }

    public function authenticate(array $request): array {
        $username = $request['username'] ?? '';
        $password = $request['password'] ?? '';
        $clientIp = $this->getClientIp();
        $fingerprint = $request['device_fingerprint'] ?? '';
        $userAgent = $_SERVER['HTTP_USER_AGENT'] ?? '';

        // LAYER 1: Global rate limit (DDoS protection)
        if ($this->isGloballyRateLimited()) {
            $this->alertSecurityTeam('global_rate_limit_triggered');
            http_response_code(503);
            return ['success' => false, 'message' => 'Service temporarily unavailable'];
        }

        // LAYER 2: IP-based rate limit (fast Redis check)
        $ipKey = "login:ip:{$clientIp}";
        if ($this->isRateLimited($ipKey, self::IP_LIMIT)) {
            $this->logSuspiciousActivity($username, $clientIp, 'ip_rate_limited', [
                'user_agent' => $userAgent,
                'fingerprint' => $fingerprint
            ]);
            return $this->rateLimitResponse();
        }

        // LAYER 3: Username-based rate limit
        $userKey = "login:user:" . hash('sha256', strtolower($username));
        if ($this->isRateLimited($userKey, self::USER_LIMIT)) {
            $this->logSuspiciousActivity($username, $clientIp, 'user_rate_limited', [
                'user_agent' => $userAgent
            ]);
            return $this->rateLimitResponse();
        }

        // LAYER 4: Device fingerprint tracking (catch residential proxies)
        if ($fingerprint && $this->isSuspiciousFingerprint($fingerprint)) {
            $this->logSuspiciousActivity($username, $clientIp, 'suspicious_fingerprint', [
                'fingerprint' => $fingerprint
            ]);
            // Don't block, but increase scrutiny
            $this->flagForCaptcha($clientIp);
        }

        // LAYER 5: Check for CAPTCHA requirement
        if ($this->requiresCaptcha($clientIp, $username)) {
            if (!$this->verifyCaptcha($request['captcha_token'] ?? '')) {
                return [
                    'success' => false,
                    'message' => 'CAPTCHA verification required',
                    'captcha_required' => true
                ];
            }
        }

        // Perform authentication
        $result = $this->performAuthentication($username, $password);

        if ($result['success']) {
            $this->onSuccessfulLogin($username, $clientIp, $fingerprint);
        } else {
            $this->onFailedLogin($username, $clientIp, $fingerprint, $userAgent);
        }

        return $result;
    }

    private function isRateLimited(string $key, int $limit): bool {
        $current = $this->redis->incr($key);
        if ($current === 1) {
            $this->redis->expire($key, self::WINDOW_SECONDS);
        }
        return $current > $limit;
    }

    private function isGloballyRateLimited(): bool {
        $key = "login:global:" . floor(time() / 60);
        $current = $this->redis->incr($key);
        if ($current === 1) {
            $this->redis->expire($key, 120);
        }
        return $current > self::GLOBAL_LIMIT;
    }

    private function isSuspiciousFingerprint(string $fingerprint): bool {
        // Check if fingerprint has been seen with many different usernames
        $key = "fingerprint:users:{$fingerprint}";
        $uniqueUsers = $this->redis->scard($key);
        return $uniqueUsers > 10; // Same device trying 10+ usernames
    }

    private function performAuthentication(string $username, string $password): array {
        try {
            $stmt = $this->pdo->prepare(
                "SELECT id, username, password_hash, mfa_enabled, account_locked 
                 FROM users WHERE username = ? AND deleted_at IS NULL"
            );
            $stmt->execute([$username]);
            $user = $stmt->fetch(PDO::FETCH_ASSOC);

            if (!$user) {
                // Timing attack prevention: always verify a password
                password_verify($password, '$2y$12$dummy.hash.to.prevent.timing.attacks');
                return ['success' => false, 'message' => 'Invalid credentials'];
            }

            if ($user['account_locked']) {
                return ['success' => false, 'message' => 'Account is locked. Contact support.'];
            }

            if (!password_verify($password, $user['password_hash'])) {
                return ['success' => false, 'message' => 'Invalid credentials'];
            }

            if ($user['mfa_enabled']) {
                $_SESSION['pending_mfa_user_id'] = $user['id'];
                return ['success' => false, 'mfa_required' => true, 'message' => 'MFA verification required'];
            }

            $this->createSession($user);
            return ['success' => true, 'message' => 'Login successful'];

        } catch (PDOException $e) {
            error_log("Authentication error: " . $e->getMessage());
            return ['success' => false, 'message' => 'Authentication service unavailable'];
        }
    }

    private function onFailedLogin(string $username, string $ip, string $fingerprint, string $userAgent): void {
        // Track fingerprint -> username mapping
        if ($fingerprint) {
            $key = "fingerprint:users:{$fingerprint}";
            $this->redis->sadd($key, hash('sha256', $username));
            $this->redis->expire($key, 3600);
        }

        // Check for credential stuffing pattern
        $this->detectCredentialStuffing($ip, $userAgent);

        // Persistent logging for forensics
        $this->logAuthEvent('login_failed', [
            'username' => $username,
            'ip' => $ip,
            'fingerprint' => substr($fingerprint, 0, 16),
            'user_agent' => $userAgent,
            'timestamp' => time()
        ]);

        // Progressive lockout: after 3 failures, require CAPTCHA
        $failKey = "login:failures:" . hash('sha256', $username);
        $failures = $this->redis->incr($failKey);
        $this->redis->expire($failKey, self::LOCKOUT_SECONDS);

        if ($failures >= 3) {
            $this->flagForCaptcha($ip);
        }

        if ($failures >= 10) {
            $this->lockAccount($username);
            $this->alertSecurityTeam('account_locked', ['username' => $username, 'ip' => $ip]);
        }
    }

    private function detectCredentialStuffing(string $ip, string $userAgent): void {
        // Track unique usernames per IP in sliding window
        $key = "stuffing:ip:{$ip}";
        $uniqueAttempts = $this->redis->pfcount($key);

        if ($uniqueAttempts > 50) {
            $this->alertSecurityTeam('credential_stuffing_detected', [
                'ip' => $ip,
                'unique_usernames' => $uniqueAttempts,
                'user_agent' => $userAgent
            ]);
            // Add to temporary blocklist
            $this->redis->setex("blocklist:ip:{$ip}", 3600, '1');
        }
    }

    private function requiresCaptcha(string $ip, string $username): bool {
        return $this->redis->exists("captcha:required:{$ip}") ||
               $this->redis->exists("captcha:required:user:" . hash('sha256', $username));
    }

    private function verifyCaptcha(string $token): bool {
        if (empty($token)) return false;

        $response = file_get_contents(
            'https://www.google.com/recaptcha/api/siteverify?secret=' . 
            urlencode(getenv('RECAPTCHA_SECRET')) . 
            '&response=' . urlencode($token)
        );
        $result = json_decode($response, true);
        return $result['success'] ?? false;
    }

    private function alertSecurityTeam(string $event, array $context = []): void {
        // Send to SIEM/alerting system
        $payload = json_encode([
            'event' => $event,
            'context' => $context,
            'timestamp' => date('c'),
            'severity' => 'high'
        ]);

        // Example: send to webhook
        $ch = curl_init(getenv('SECURITY_WEBHOOK_URL'));
        curl_setopt_array($ch, [
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => $payload,
            CURLOPT_HTTPHEADER => ['Content-Type: application/json'],
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_TIMEOUT => 5
        ]);
        curl_exec($ch);
        curl_close($ch);
    }

    private function rateLimitResponse(): array {
        http_response_code(429);
        header('Retry-After: ' . self::LOCKOUT_SECONDS);
        return [
            'success' => false,
            'message' => 'Too many login attempts. Please try again later.',
            'retry_after' => self::LOCKOUT_SECONDS
        ];
    }

    private function getClientIp(): string {
        // Handle proxies but validate format
        $ip = $_SERVER['HTTP_X_FORWARDED_FOR'] ?? $_SERVER['REMOTE_ADDR'] ?? '0.0.0.0';
        $ip = explode(',', $ip)[0];
        return filter_var(trim($ip), FILTER_VALIDATE_IP) ?: '0.0.0.0';
    }

    private function createSession(array $user): void {
        session_regenerate_id(true);
        $_SESSION['user_id'] = $user['id'];
        $_SESSION['username'] = $user['username'];
        $_SESSION['created_at'] = time();
    }

    private function flagForCaptcha(string $ip): void {
        $this->redis->setex("captcha:required:{$ip}", self::LOCKOUT_SECONDS, '1');
    }

    private function lockAccount(string $username): void {
        $stmt = $this->pdo->prepare(
            "UPDATE users SET account_locked = 1, locked_at = NOW() WHERE username = ?"
        );
        $stmt->execute([$username]);
    }

    private function logAuthEvent(string $event, array $data): void {
        error_log(json_encode(['event' => $event, 'data' => $data]));
    }

    private function logSuspiciousActivity(string $username, string $ip, string $event, array $extra = []): void {
        $this->logAuthEvent('suspicious_activity', array_merge([
            'event' => $event,
            'username' => $username,
            'ip' => $ip
        ], $extra));
    }
}
