Great question! The Have I Been Pwned API uses k-anonymity to check passwords without exposing them. You send only the first 5 characters of the SHA-1 hash, and the API returns all breached password hashes starting with those characters. You then check locally if your full hash matches.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net.Http;
using System.Security.Cryptography;
using System.Text;
using System.Text.RegularExpressions;
using System.Threading.Tasks;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;

namespace SecureApp.Services
{
    public interface IPasswordValidator
    {
        Task<PasswordValidationResult> ValidateAsync(string password, string username);
    }

    public class PasswordValidationResult
    {
        public bool IsValid { get; set; }
        public List<string> Errors { get; set; } = new List<string>();
    }

    public class SecurePasswordValidator : IPasswordValidator
    {
        private readonly HttpClient _httpClient;
        private readonly IMemoryCache _cache;
        private readonly ILogger<SecurePasswordValidator> _logger;

        // NIST SP 800-63B compliant settings
        private const int MinimumLength = 12;
        private const int MaximumLength = 128;
        private const int BreachThreshold = 3; // Allow if fewer than 3 breaches (configurable)

        private static readonly HashSet<string> CommonPatterns = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "password", "qwerty", "123456", "admin", "letmein", "welcome",
            "monkey", "dragon", "master", "login", "abc123", "111111"
        };

        public SecurePasswordValidator(
            IHttpClientFactory httpClientFactory,
            IMemoryCache cache,
            ILogger<SecurePasswordValidator> logger)
        {
            _httpClient = httpClientFactory.CreateClient("HIBP");
            _httpClient.DefaultRequestHeaders.Add("User-Agent", "SecureApp-PasswordChecker");
            _cache = cache;
            _logger = logger;
        }

        public async Task<PasswordValidationResult> ValidateAsync(string password, string username)
        {
            var result = new PasswordValidationResult { IsValid = true };

            // Layer 1: Length requirements (NIST recommends 8+, we use 12+)
            if (string.IsNullOrEmpty(password) || password.Length < MinimumLength)
            {
                result.IsValid = false;
                result.Errors.Add($"Password must be at least {MinimumLength} characters long");
            }

            if (password?.Length > MaximumLength)
            {
                result.IsValid = false;
                result.Errors.Add($"Password cannot exceed {MaximumLength} characters");
            }

            if (string.IsNullOrEmpty(password))
            {
                return result;
            }

            // Layer 2: Complexity requirements
            var complexityErrors = ValidateComplexity(password);
            if (complexityErrors.Any())
            {
                result.IsValid = false;
                result.Errors.AddRange(complexityErrors);
            }

            // Layer 3: Context-specific checks (username similarity)
            if (!string.IsNullOrEmpty(username) && 
                password.Contains(username, StringComparison.OrdinalIgnoreCase))
            {
                result.IsValid = false;
                result.Errors.Add("Password cannot contain your username");
            }

            // Layer 4: Common password patterns
            if (ContainsCommonPattern(password))
            {
                result.IsValid = false;
                result.Errors.Add("Password contains a commonly used word or pattern");
            }

            // Layer 5: Repetitive/sequential characters
            if (HasRepetitiveOrSequentialChars(password))
            {
                result.IsValid = false;
                result.Errors.Add("Password cannot contain repetitive or sequential characters");
            }

            // Layer 6: Check against breached passwords (k-anonymity)
            try
            {
                var breachCount = await CheckBreachedPasswordAsync(password);
                if (breachCount >= BreachThreshold)
                {
                    result.IsValid = false;
                    result.Errors.Add($"This password has appeared in {breachCount:N0} data breaches. Please choose a different password.");
                }
            }
            catch (Exception ex)
            {
                // Fail open but log - don't block registration if HIBP is down
                _logger.LogWarning(ex, "Failed to check password against breach database");
            }

            return result;
        }

        private List<string> ValidateComplexity(string password)
        {
            var errors = new List<string>();

            if (!Regex.IsMatch(password, @"[a-z]"))
                errors.Add("Password must contain at least one lowercase letter");

            if (!Regex.IsMatch(password, @"[A-Z]"))
                errors.Add("Password must contain at least one uppercase letter");

            if (!Regex.IsMatch(password, @"[0-9]"))
                errors.Add("Password must contain at least one number");

            if (!Regex.IsMatch(password, @"[!@#$%^&*()_+\-=\[\]{};':""\\|,.<>\/?]"))
                errors.Add("Password must contain at least one special character");

            return errors;
        }

        private bool ContainsCommonPattern(string password)
        {
            string lowerPassword = password.ToLowerInvariant();
            return CommonPatterns.Any(pattern => lowerPassword.Contains(pattern));
        }

        private bool HasRepetitiveOrSequentialChars(string password)
        {
            // Check for 3+ repeating characters (aaa, 111)
            if (Regex.IsMatch(password, @"(.)\1{2,}"))
                return true;

            // Check for sequential characters (abc, 123, cba, 321)
            for (int i = 0; i < password.Length - 2; i++)
            {
                if ((password[i + 1] == password[i] + 1 && password[i + 2] == password[i] + 2) ||
                    (password[i + 1] == password[i] - 1 && password[i + 2] == password[i] - 2))
                {
                    return true;
                }
            }

            return false;
        }

        private async Task<int> CheckBreachedPasswordAsync(string password)
        {
            // K-ANONYMITY: Only send first 5 chars of SHA-1 hash
            using (var sha1 = SHA1.Create())
            {
                byte[] hashBytes = sha1.ComputeHash(Encoding.UTF8.GetBytes(password));
                string fullHash = BitConverter.ToString(hashBytes).Replace("-", "");

                string prefix = fullHash.Substring(0, 5);
                string suffix = fullHash.Substring(5);

                // Cache responses to reduce API calls
                string cacheKey = $"hibp_{prefix}";
                if (!_cache.TryGetValue(cacheKey, out Dictionary<string, int> hashSuffixes))
                {
                    var response = await _httpClient.GetAsync(
                        $"https://api.pwnedpasswords.com/range/{prefix}");

                    response.EnsureSuccessStatusCode();
                    string responseBody = await response.Content.ReadAsStringAsync();

                    hashSuffixes = ParseHIBPResponse(responseBody);

                    // Cache for 1 hour
                    _cache.Set(cacheKey, hashSuffixes, TimeSpan.FromHours(1));
                }

                // Check if our suffix is in the breached list
                return hashSuffixes.TryGetValue(suffix, out int count) ? count : 0;
            }
        }

        private Dictionary<string, int> ParseHIBPResponse(string response)
        {
