            foreach (var line in response.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                var parts = line.Trim().Split(':');
                if (parts.Length == 2 && int.TryParse(parts[1], out int count))
                {
                    result[parts[0]] = count;
                }
            }

            return result;
