    RESET_TOKEN_EXPIRY = 3600  # 1 hour

    @classmethod
    def generate_reset_token(cls, user_id, user_email):
        """Generate secure reset token with metadata"""
        token = secrets.token_urlsafe(cls.TOKEN_LENGTH)
        token_hash = hashlib.sha256(token.encode()).hexdigest()

        # Store hashed token with metadata
        token_data = {
