            'email': user_email,
            'created_at': datetime.utcnow().isoformat(),
            'used': 'false'
        }

        redis_client.hset(f'reset_token:{token_hash}', mapping=token_data)
        redis_client.expire(f'reset_token:{token_hash}', cls.RESET_TOKEN_EXPIRY)

        return token

    @classmethod
    def validate_reset_token(cls, token):
        """Validate and consume reset token (one-time use)"""
        token_hash = hashlib.sha256(token.encode()).hexdigest()
        token_key = f'reset_token:{token_hash}'

        token_data = redis_client.hgetall(token_key)

        if not token_data:
