  async getDelayMs(failedAttempts) {
    // Progressive delay: 0, 1s, 2s, 4s, 8s, 16s, 30s max
    const delay = Math.min(Math.pow(2, failedAttempts - 1) * 1000, 30000);
    return failedAttempts > 0 ? delay : 0;
  }
}

