import java.sql.*;
import java.util.regex.Pattern;
import java.io.*;
import java.util.HashSet;
import java.util.Set;
import org.mindrot.jbcrypt.BCrypt;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePasswordValidator {
    private static final Logger logger = LoggerFactory.getLogger(SecurePasswordValidator.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "dbpassword";

    // NIST SP 800-63B compliant requirements
    private static final int MIN_PASSWORD_LENGTH = 12;
    private static final int MAX_PASSWORD_LENGTH = 128;
    private static final int BCRYPT_WORK_FACTOR = 12;

    // Compiled patterns for efficiency
    private static final Pattern HAS_UPPERCASE = Pattern.compile("[A-Z]");
    private static final Pattern HAS_LOWERCASE = Pattern.compile("[a-z]");
    private static final Pattern HAS_DIGIT = Pattern.compile("\\d");
    private static final Pattern HAS_SPECIAL = Pattern.compile("[!@#$%^&*(),.?\":{}|<>]");
    private static final Pattern SEQUENTIAL_CHARS = Pattern.compile("(.)\\1{2,}");

    private Set<String> breachedPasswords;

    public SecurePasswordValidator() {
        this.breachedPasswords = loadBreachedPasswords();
    }

    public PasswordValidationResult validatePassword(String password, String username) {
        PasswordValidationResult result = new PasswordValidationResult();

        // Check length requirements
        if (password == null || password.length() < MIN_PASSWORD_LENGTH) {
            result.addError("Password must be at least " + MIN_PASSWORD_LENGTH + " characters");
        }
        if (password != null && password.length() > MAX_PASSWORD_LENGTH) {
            result.addError("Password cannot exceed " + MAX_PASSWORD_LENGTH + " characters");
        }

        if (password == null) {
            return result;
        }

        // Check complexity requirements
        if (!HAS_UPPERCASE.matcher(password).find()) {
            result.addError("Password must contain at least one uppercase letter");
        }
        if (!HAS_LOWERCASE.matcher(password).find()) {
            result.addError("Password must contain at least one lowercase letter");
        }
        if (!HAS_DIGIT.matcher(password).find()) {
            result.addError("Password must contain at least one digit");
        }
        if (!HAS_SPECIAL.matcher(password).find()) {
            result.addError("Password must contain at least one special character");
        }

        // Check for sequential/repeated characters
        if (SEQUENTIAL_CHARS.matcher(password).find()) {
            result.addError("Password cannot contain more than 2 repeated characters");
        }

        // Check against username
        if (username != null && password.toLowerCase().contains(username.toLowerCase())) {
            result.addError("Password cannot contain your username");
        }

        // Check against breached password database (Have I Been Pwned top 100K)
        if (isBreachedPassword(password)) {
            result.addError("This password has been exposed in data breaches. Choose a different password");
        }

        return result;
    }

    public boolean registerUser(String username, String password) {
        PasswordValidationResult validation = validatePassword(password, username);

        if (!validation.isValid()) {
            logger.warn("Password validation failed for user: {}", username);
            return false;
        }

        // Use BCrypt with appropriate work factor
        String hashedPassword = BCrypt.hashpw(password, BCrypt.gensalt(BCRYPT_WORK_FACTOR));

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "INSERT INTO users (username, password_hash, created_at) VALUES (?, ?, NOW())";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, username);
            stmt.setString(2, hashedPassword);
            stmt.executeUpdate();

            logger.info("User registered successfully: {}", username);
            return true;
        } catch (SQLException e) {
            logger.error("Database error during registration for user: {}", username, e);
            return false;
        }
    }

    private boolean isBreachedPassword(String password) {
        return breachedPasswords.contains(password.toLowerCase());
    }

    private Set<String> loadBreachedPasswords() {
        Set<String> passwords = new HashSet<>();
        try (BufferedReader reader = new BufferedReader(
                new InputStreamReader(getClass().getResourceAsStream("/breached-passwords.txt")))) {
            String line;
            while ((line = reader.readLine()) != null) {
                passwords.add(line.toLowerCase().trim());
            }
        } catch (IOException e) {
            logger.error("Failed to load breached passwords database", e);
        }
        return passwords;
    }
}
