import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.Timer;

public class ProductionPasswordService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionPasswordService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    // Configuration
    private static final int MIN_PASSWORD_LENGTH = 12;
    private static final int MAX_PASSWORD_LENGTH = 128;
    private static final int BCRYPT_WORK_FACTOR = 12;
    private static final String HIBP_API_URL = "https://api.pwnedpasswords.com/range/";
    private static final Duration API_TIMEOUT = Duration.ofSeconds(5);

    private final HttpClient httpClient;
    private final MeterRegistry meterRegistry;
    private final Counter breachedPasswordCounter;
    private final Counter weakPasswordCounter;
    private final Timer passwordValidationTimer;
    private final ExecutorService executor;
    private final Cache<String, Boolean> breachCache;

    public ProductionPasswordService(MeterRegistry meterRegistry) {
        this.meterRegistry = meterRegistry;
        this.httpClient = HttpClient.newBuilder()
            .connectTimeout(API_TIMEOUT)
            .build();
        this.executor = Executors.newFixedThreadPool(4);
        this.breachCache = new ConcurrentHashMap<>();

        // Metrics for monitoring
        this.breachedPasswordCounter = Counter.builder("password.breached")
            .description("Count of breached passwords detected")
            .register(meterRegistry);
        this.weakPasswordCounter = Counter.builder("password.weak")
            .description("Count of weak passwords rejected")
            .register(meterRegistry);
        this.passwordValidationTimer = Timer.builder("password.validation.time")
            .description("Time spent validating passwords")
            .register(meterRegistry);
    }

    public PasswordStrengthResult analyzePassword(String password, String username, String email) {
        return passwordValidationTimer.record(() -> {
            PasswordStrengthResult result = new PasswordStrengthResult();

            if (password == null || password.isEmpty()) {
                result.setScore(0);
                result.setStrength(PasswordStrength.VERY_WEAK);
                result.addFeedback("Password is required");
                return result;
            }

            int score = 0;
            List<String> feedback = new ArrayList<>();

            // Length scoring (0-30 points)
            int length = password.length();
            if (length >= MIN_PASSWORD_LENGTH) {
                score += Math.min(30, (length - MIN_PASSWORD_LENGTH + 1) * 3);
            } else {
                feedback.add("Use at least " + MIN_PASSWORD_LENGTH + " characters");
            }

            // Character variety scoring (0-40 points)
            boolean hasUpper = password.chars().anyMatch(Character::isUpperCase);
            boolean hasLower = password.chars().anyMatch(Character::isLowerCase);
            boolean hasDigit = password.chars().anyMatch(Character::isDigit);
            boolean hasSpecial = password.chars().anyMatch(c -> !Character.isLetterOrDigit(c));

            int varietyCount = 0;
            if (hasUpper) varietyCount++;
            else feedback.add("Add uppercase letters");
            if (hasLower) varietyCount++;
            else feedback.add("Add lowercase letters");
            if (hasDigit) varietyCount++;
            else feedback.add("Add numbers");
            if (hasSpecial) varietyCount++;
            else feedback.add("Add special characters (!@#$%^&*)");

            score += varietyCount * 10;

            // Entropy estimation (0-20 points)
            double entropy = calculateEntropy(password);
            score += Math.min(20, (int)(entropy / 4));

            // Penalty for common patterns (-20 points each)
            if (containsCommonPattern(password)) {
                score -= 20;
                feedback.add("Avoid common patterns like '123', 'abc', or keyboard sequences");
            }

            // Penalty for personal info (-30 points)
            if (containsPersonalInfo(password, username, email)) {
                score -= 30;
                feedback.add("Don't use your username or email in your password");
            }

            // Check breach status asynchronously
            CompletableFuture<Boolean> breachCheck = checkBreachedPasswordAsync(password);
            try {
                boolean isBreached = breachCheck.get(API_TIMEOUT.toMillis(), TimeUnit.MILLISECONDS);
                if (isBreached) {
                    score = 0; // Breached passwords get zero score
                    feedback.clear();
                    feedback.add("This password has appeared in data breaches. Choose a completely different password.");
                    breachedPasswordCounter.increment();
                    auditLogger.warn("Breached password attempt detected");
                }
            } catch (TimeoutException e) {
                logger.warn("HIBP API timeout, proceeding with local validation only");
            } catch (Exception e) {
                logger.error("Error checking breached password", e);
            }

            // Calculate final strength
            score = Math.max(0, Math.min(100, score));
            result.setScore(score);
            result.setStrength(calculateStrength(score));
            result.setFeedback(feedback);
            result.setEntropy(entropy);

            if (score < 50) {
                weakPasswordCounter.increment();
            }

            return result;
        });
    }

    public CompletableFuture<Boolean> checkBreachedPasswordAsync(String password) {
        return CompletableFuture.supplyAsync(() -> {
            try {
                // Use k-anonymity: only send first 5 chars of SHA-1 hash
                String sha1Hash = sha1Hash(password).toUpperCase();
                String prefix = sha1Hash.substring(0, 5);
                String suffix = sha1Hash.substring(5);

                // Check cache first
                String cacheKey = prefix;
                if (breachCache.containsKey(cacheKey + ":" + suffix)) {
                    return breachCache.get(cacheKey + ":" + suffix);
                }

                HttpRequest request = HttpRequest.newBuilder()
                    .uri(URI.create(HIBP_API_URL + prefix))
                    .header("User-Agent", "PasswordValidator/1.0")
                    .header("Add-Padding", "true") // Prevent timing attacks
                    .timeout(API_TIMEOUT)
                    .GET()
                    .build();

                HttpResponse<String> response = httpClient.send(request, 
                    HttpResponse.BodyHandlers.ofString());

                if (response.statusCode() == 200) {
                    String[] lines = response.body().split("\n");
                    for (String line : lines) {
                        String[] parts = line.split(":");
                        if (parts.length >= 1 && parts[0].trim().equals(suffix)) {
                            breachCache.put(cacheKey + ":" + suffix, true);
                            return true;
                        }
                    }
                }

                breachCache.put(cacheKey + ":" + suffix, false);
                return false;

            } catch (Exception e) {
                logger.warn("Failed to check HIBP API: {}", e.getMessage());
                return false; // Fail open but log for monitoring
            }
        }, executor);
    }

    public String hashPassword(String password) {
        return BCrypt.hashpw(password, BCrypt.gensalt(BCRYPT_WORK_FACTOR));
    }

    public boolean verifyPassword(String password, String hashedPassword) {
        try {
            return BCrypt.checkpw(password, hashedPassword);
        } catch (Exception e) {
            logger.error("Password verification error", e);
            return false;
        }
    }

    private double calculateEntropy(String password) {
        Map<Character, Integer> charCounts = new HashMap<>();
        for (char c : password.toCharArray()) {
            charCounts.merge(c, 1, Integer::sum);
        }

        double entropy = 0.0;
        int length = password.length();
        for (int count : charCounts.values()) {
            double probability = (double) count / length;
            entropy -= probability * (Math.log(probability) / Math.log(2));
        }

        return entropy * length;
    }

    private boolean containsCommonPattern(String password) {
        String lower = password.toLowerCase();
        String[] patterns = {
            "123456", "password", "qwerty", "abc123", "letmein",
            "welcome", "admin", "login", "master", "dragon",
            "1234567890", "abcdefgh", "qwertyuiop", "asdfghjkl"
        };

        for (String pattern : patterns) {
            if (lower.contains(pattern)) {
                return true;
            }
        }

        // Check for keyboard sequences
        String[] keyboardRows = {"qwertyuiop", "asdfghjkl", "zxcvbnm"};
        for (String row : keyboardRows) {
            for (int i = 0; i <= row.length() - 4; i++) {
                if (lower.contains(row.substring(i, i + 4))) {
                    return true;
                }
            }
        }

        return false;
    }

    private boolean containsPersonalInfo(String password, String username, String email) {
        String lower = password.toLowerCase();

        if (username != null && username.length() >= 3 && 
            lower.contains(username.toLowerCase())) {
            return true;
        }

        if (email != null) {
            String emailPrefix = email.split("@")[0].toLowerCase();
            if (emailPrefix.length() >= 3 && lower.contains(emailPrefix)) {
                return true;
            }
        }

        return false;
    }

    private PasswordStrength calculateStrength(int score) {
        if (score >= 80) return PasswordStrength.VERY_STRONG;
        if (score >= 60) return PasswordStrength.STRONG;
        if (score >= 40) return PasswordStrength.MODERATE;
        if (score >= 20) return PasswordStrength.WEAK;
        return PasswordStrength.VERY_WEAK;
    }

    private String sha1Hash(String input) {
        try {
            MessageDigest md = MessageDigest.getInstance("SHA-1");
            byte[] hash = md.digest(input.getBytes(StandardCharsets.UTF_8));
            StringBuilder hexString = new StringBuilder();
            for (byte b : hash) {
                hexString.append(String.format("%02x", b));
            }
            return hexString.toString();
        } catch (Exception e) {
            throw new RuntimeException("SHA-1 not available", e);
        }
    }

    public enum PasswordStrength {
        VERY_WEAK, WEAK, MODERATE, STRONG, VERY_STRONG
    }

    public static class PasswordStrengthResult {
        private int score;
        private PasswordStrength strength;
        private List<String> feedback = new ArrayList<>();
        private double entropy;

        public void setScore(int score) { this.score = score; }
        public int getScore() { return score; }
        public void setStrength(PasswordStrength strength) { this.strength = strength; }
        public PasswordStrength getStrength() { return strength; }
        public void setFeedback(List<String> feedback) { this.feedback = feedback; }
        public void addFeedback(String msg) { this.feedback.add(msg); }
        public List<String> getFeedback() { return feedback; }
        public void setEntropy(double entropy) { this.entropy = entropy; }
        public double getEntropy() { return entropy; }
        public boolean isAcceptable() { return score >= 60; }
    }
}
